const textResponse = $('OpenAI Chat1').item.json.message.content;
const audioData = $input.item.binary.data;

return {
  json: {
    text: textResponse,
    audio_base64: audioData.data,
    session_id: $('Webhook Entrada').item.json.body?.session_id || $('Webhook Entrada').item.json.session_id || 'default'
  }
};

// Obtener información de la llamada
const callSid = $input.item.json.CallSid || 'test-call';
const from = $input.item.json.From || '+57000000000';
const speechResult = $input.item.json.SpeechResult || '';
const isFirstCall = !$input.item.json.SpeechResult;

// Obtener contexto previo de esta llamada
let context = global.get(`call_${callSid}`) || {
  telefono: from,
  conversacion: [],
  step: 0
};

// Mensaje del usuario
let userMessage = speechResult || 'Hola';

// Agregar al historial
if (speechResult || isFirstCall) {
  context.conversacion.push({
    role: 'user',
    content: userMessage
  });
}

// Guardar contexto
global.set(`call_${callSid}`, context);

return [{
  json: {
    callSid,
    from,
    userMessage,
    context,
    isFirstCall
  }
}];

// Obtener respuesta del AI Agent
const aiResponse = $input.item.json.output || $input.item.json.text || '';
const callSid = $('Procesar Llamada').item.json.callSid;

// Actualizar contexto con la respuesta de la IA
let context = global.get(`call_${callSid}`) || {};
context.conversacion = context.conversacion || [];

context.conversacion.push({
  role: 'assistant',
  content: aiResponse
});

// Detectar si la IA mencionó que agendó la cita (señal de finalización)
const mensajeLower = aiResponse.toLowerCase();
const citaAgendada = mensajeLower.includes('agendada') || 
                     mensajeLower.includes('agendé') || 
                     mensajeLower.includes('confirmada') ||
                     mensajeLower.includes('listo');

context.citaAgendada = citaAgendada;

// Guardar contexto
global.set(`call_${callSid}`, context);

return [{
  json: {
    aiResponse,
    citaAgendada,
    callSid,
    context
  }
}];

